const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base   = 'YOUR_SUPABASE_REST_URL';
const hdr    = { apikey, Authorization: `Bearer ${apikey}` };

const now = new Date();
const centralStr = now.toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const centralHour = Number(now.toLocaleString('en-US', { timeZone: 'America/Chicago', hour: 'numeric', hour12: false }));

const centralNow = new Date(now.toLocaleString('en-US', { timeZone: 'America/Chicago' }));
const dayOfWeek = centralNow.getDay();
const mondayOffset = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
const monday = new Date(centralNow);
monday.setDate(monday.getDate() - mondayOffset);
const mondayStr = monday.toISOString().slice(0, 10);

const [roster, weeklyData, intradayData, pipelineData, poolData] = await Promise.all([
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/agents?select=name,site,tier,manager&is_active=eq.true`,
    headers: hdr, json: true,
  }),
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/daily_scrape_data?select=agent_name,scrape_date,ib_leads_delivered,ob_leads_delivered,ib_sales,ob_sales,custom_sales&scrape_date=gte.${mondayStr}&scrape_date=lte.${centralStr}&order=scrape_date.asc`,
    headers: hdr, json: true,
  }),
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/intraday_snapshots?select=agent_name,scrape_hour,total_dials,talk_time_minutes,ib_leads_delivered,ib_sales,ob_leads_delivered,ob_sales,ib_premium,ob_premium,custom_premium,pool_dials,pool_talk_minutes,pool_self_assigned,pool_answered,pool_long_calls&scrape_date=eq.${centralStr}&order=scrape_hour.desc`,
    headers: hdr, json: true,
  }),
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/pipeline_compliance_daily?select=agent_name,past_due_follow_ups,new_leads,call_queue_count,todays_follow_ups&scrape_date=eq.${centralStr}`,
    headers: hdr, json: true,
  }),
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/leads_pool_daily_data?select=agent_name,calls_made,talk_time_minutes,self_assigned_leads,answered_calls,long_calls,sales_made&scrape_date=eq.${centralStr}`,
    headers: hdr, json: true,
  }),
]);

if (!roster || roster.length === 0) {
  throw new Error('No active agents found');
}

const rosterMap = {};
for (const a of roster) rosterMap[a.name] = a;

const weeklyByAgent = {};
for (const r of (weeklyData || [])) {
  if (!rosterMap[r.agent_name]) continue;
  if (!weeklyByAgent[r.agent_name]) weeklyByAgent[r.agent_name] = [];
  weeklyByAgent[r.agent_name].push({
    date: r.scrape_date,
    ibLeads: r.ib_leads_delivered || 0,
    obLeads: r.ob_leads_delivered || 0,
    ibSales: r.ib_sales || 0,
    obSales: r.ob_sales || 0,
    customSales: r.custom_sales || 0,
  });
}

const intradayMap = {};
for (const r of (intradayData || [])) {
  if (!intradayMap[r.agent_name] && rosterMap[r.agent_name]) {
    intradayMap[r.agent_name] = r;
  }
}

const pipeMap = {};
for (const r of (pipelineData || [])) {
  if (rosterMap[r.agent_name]) pipeMap[r.agent_name] = r;
}

const poolMapData = {};
for (const r of (poolData || [])) {
  if (rosterMap[r.agent_name]) poolMapData[r.agent_name] = r;
}

return [{
  json: {
    scrapeDate: centralStr,
    centralHour,
    mondayStr,
    rosterMap,
    weeklyByAgent,
    intradayMap,
    pipeMap,
    poolMapData,
    agentCount: roster.length,
  }
}];

const { scrapeDate, centralHour, rosterMap, weeklyByAgent, intradayMap, pipeMap, poolMapData, agentCount } = $input.first().json;

const CFG = { CR_TARGET: 15, CR_FLOOR: 10, CR_CRISIS: 7, CR_CRISIS_DAYS: 3, MAX_PIPELINE: 30, LEAD_COST: 60, POOL_FOLLOWUPS: 5 };

function computeWeeklyCR(rows) {
  if (!rows || rows.length === 0) return { weeklyCR: null, dailyCRs: [] };
  const dailyCRs = rows.map(r => {
    const leads = r.ibLeads + r.obLeads;
    const sales = r.ibSales + r.obSales + r.customSales;
    return leads > 0 ? (sales / leads) * 100 : 0;
  });
  const totalL = rows.reduce((s, r) => s + r.ibLeads + r.obLeads, 0);
  const totalS = rows.reduce((s, r) => s + r.ibSales + r.obSales + r.customSales, 0);
  return { weeklyCR: totalL > 0 ? (totalS / totalL) * 100 : null, dailyCRs };
}

function consLow(dailyCRs, threshold) {
  let c = 0;
  for (let i = dailyCRs.length - 1; i >= 0; i--) { if (dailyCRs[i] < threshold) c++; else break; }
  return c;
}

function recommend(weeklyCR, dailyCRs, pipe, intra, pool) {
  const pastDue = pipe?.past_due_follow_ups ?? 0;
  const pipeSize = (pipe?.new_leads ?? 0) + (pipe?.todays_follow_ups ?? 0) + pastDue;
  const poolSelfAssigned = pool?.self_assigned_leads ?? 0;
  const poolDials = pool?.calls_made ?? 0;
  const consLowDays = consLow(dailyCRs, CFG.CR_CRISIS);

  if (pastDue > 0) return { action: 'WORK_FOLLOWUPS', severity: 'critical', reason: `${pastDue} past due follow-up${pastDue > 1 ? 's' : ''} — $${pastDue * CFG.LEAD_COST} at risk.` };
  if (pipeSize > CFG.MAX_PIPELINE) return { action: 'CLEAR_PIPELINE', severity: 'critical', reason: `Pipeline at ${pipeSize} leads (max ${CFG.MAX_PIPELINE}).` };
  if (consLowDays >= CFG.CR_CRISIS_DAYS && weeklyCR !== null) return { action: 'REVIEW_QUALITY', severity: 'critical', reason: `CR below ${CFG.CR_CRISIS}% for ${consLowDays} days (weekly: ${weeklyCR.toFixed(0)}%).` };
  if (weeklyCR !== null && weeklyCR < CFG.CR_FLOOR) return { action: 'WORK_FOLLOWUPS', severity: 'warning', reason: `Weekly CR at ${weeklyCR.toFixed(0)}% (floor: ${CFG.CR_FLOOR}%). Focus on converting pipeline.` };
  if (poolSelfAssigned < CFG.POOL_FOLLOWUPS && (intra?.talk_time_minutes ?? 0) > 60) return { action: 'GET_IN_POOL', severity: 'warning', reason: `Only ${poolSelfAssigned} pool assigns today (target: ${CFG.POOL_FOLLOWUPS}). Find 5 people from pool to follow up with.` };
  if (weeklyCR !== null && weeklyCR >= CFG.CR_TARGET && pipeSize < 20 && pastDue === 0) return { action: 'TAKE_MORE_LEADS', severity: 'info', reason: `CR at ${weeklyCR.toFixed(0)}% with clean pipeline. Eligible for >7 leads/day.` };
  if (pipeSize < 10 && poolDials === 0) return { action: 'GET_IN_POOL', severity: 'info', reason: `Light pipeline at ${pipeSize}. Pool session will build follow-up pipeline.` };
  return { action: 'ON_TRACK', severity: 'info', reason: `${weeklyCR !== null ? 'CR ' + weeklyCR.toFixed(0) + '%' : ''} · Pipeline ${pipeSize} · Pool assigns ${poolSelfAssigned} — on track.` };
}

const results = [];
for (const [name, agent] of Object.entries(rosterMap)) {
  const weekRows = weeklyByAgent[name] || [];
  const { weeklyCR, dailyCRs } = computeWeeklyCR(weekRows);
  const pipe = pipeMap[name];
  const pool = poolMapData[name];
  const intra = intradayMap[name];

  const rec = recommend(weeklyCR, dailyCRs, pipe, intra, pool);

  const poolDials = pool?.calls_made ?? 0;
  const poolSelfAssigned = pool?.self_assigned_leads ?? 0;
  const totalDials = intra?.total_dials ?? 0;
  const todaysLeads = (intra?.ib_leads_delivered ?? 0) + (intra?.ob_leads_delivered ?? 0);
  const todaysSales = (intra?.ib_sales ?? 0) + (intra?.ob_sales ?? 0);
  const todaysCR = todaysLeads > 0 ? (todaysSales / todaysLeads) * 100 : null;

  results.push({
    name, tier: agent.tier, site: agent.site, manager: agent.manager || null,
    ...rec,
    weeklyCR: weeklyCR !== null ? Math.round(weeklyCR * 10) / 10 : null,
    todaysCR: todaysCR !== null ? Math.round(todaysCR * 10) / 10 : null,
    pastDue: pipe?.past_due_follow_ups ?? null,
    pipelineSize: pipe ? (pipe.new_leads ?? 0) + (pipe.todays_follow_ups ?? 0) + (pipe.past_due_follow_ups ?? 0) : null,
    poolDials, poolSelfAssigned,
    todaysLeads, todaysSales, todaysDials: totalDials,
    todaysTalkMin: Math.round(intra?.talk_time_minutes ?? 0),
  });
}

const sev = { critical: 0, warning: 1, info: 2 };
results.sort((a, b) => sev[a.severity] - sev[b.severity]);

const critical = results.filter(r => r.severity === 'critical');
const warning  = results.filter(r => r.severity === 'warning');
const onTrack  = results.filter(r => r.severity === 'info');

return [{ json: {
  scrapeDate, centralHour, agentCount,
  critical, warning, onTrack, results,
} }];

const { scrapeDate, centralHour, critical, warning, onTrack, agentCount } = $input.first().json;

const [y, mo, d] = scrapeDate.split('-');
const dt = new Date(+y, +mo - 1, +d);
const dn = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][dt.getDay()];
const mn = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][dt.getMonth()];
const dd = `${dn} ${mn} ${+d}, ${y}`;
const ampm = centralHour > 12 ? `${centralHour - 12}:05 PM` : centralHour === 12 ? '12:05 PM' : `${centralHour}:05 AM`;

const ACTION_LABELS = {
  TAKE_MORE_LEADS: 'TAKE MORE LEADS',
  WORK_FOLLOWUPS: 'WORK FOLLOW-UPS',
  GET_IN_POOL: 'GET IN POOL',
  CLEAR_PIPELINE: 'CLEAR PIPELINE',
  REVIEW_QUALITY: 'REVIEW QUALITY',
  ON_TRACK: 'ON TRACK',
};

const blocks = [];

blocks.push({ type: 'header', text: { type: 'plain_text', text: `Hourly Alert — ${dd}` } });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text:
  `*${ampm} CT*  ·  ${agentCount} agents tracked\n` +
  `*${critical.length}* :rotating_light: critical  ·  *${warning.length}* :warning: warning  ·  *${onTrack.length}* :white_check_mark: on track`
}});

blocks.push({ type: 'divider' });

function formatAgent(a) {
  const crStr = a.weeklyCR !== null ? `Weekly CR: ${a.weeklyCR}%` : 'No CR data';
  const todayCR = a.todaysCR !== null ? `Today: ${a.todaysCR}%` : '';
  const leads = `Leads: ${a.todaysLeads}`;
  const sales = `Sales: ${a.todaysSales}`;
  const pool = a.poolDials > 0 ? `Pool: ${a.poolDials} dials / ${a.poolSelfAssigned} assigns` : '';
  const pd = a.pastDue !== null ? `Past Due: ${a.pastDue}` : '';
  const pipe = a.pipelineSize !== null ? `Pipeline: ${a.pipelineSize}` : '';
  const stats = [leads, sales, crStr, todayCR, pool, pd, pipe].filter(Boolean).join(' · ');
  return `*${ACTION_LABELS[a.action]}* — *${a.name}*  _(${a.site})_\n${stats}\n_↳ ${a.reason}_`;
}

if (critical.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*:rotating_light: CRITICAL (${critical.length})*` } });
  for (const a of critical.slice(0, 12)) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: formatAgent(a) } });
  }
  if (critical.length > 12) {
    blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `_…and ${critical.length - 12} more critical._` }] });
  }
  blocks.push({ type: 'divider' });
}

if (warning.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*:warning: WARNING (${warning.length})*` } });
  for (const a of warning.slice(0, 12)) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: formatAgent(a) } });
  }
  if (warning.length > 12) {
    blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `_…and ${warning.length - 12} more warnings._` }] });
  }
  blocks.push({ type: 'divider' });
}

const rmtTrack = onTrack.filter(a => a.site === 'RMT');
const cltTrack = onTrack.filter(a => a.site === 'CHA');
const otherTrack = onTrack.filter(a => a.site !== 'RMT' && a.site !== 'CHA');

const trackLines = [];
if (rmtTrack.length > 0) trackLines.push(`*RMT* (${rmtTrack.length}): ${rmtTrack.map(a => a.name).join(', ')}`);
if (cltTrack.length > 0) trackLines.push(`*CLT* (${cltTrack.length}): ${cltTrack.map(a => a.name).join(', ')}`);
if (otherTrack.length > 0) trackLines.push(`*Other* (${otherTrack.length}): ${otherTrack.map(a => a.name).join(', ')}`);

if (trackLines.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*:white_check_mark: ON TRACK (${onTrack.length})*\n${trackLines.join('\n')}` } });
  blocks.push({ type: 'divider' });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text:
  `Unified model: 7 IB leads/day · CR target 15%+ · Pipeline ≤30 · Pool: 5 assigns/day`
}]});

const fallback = `Hourly Alert — ${dd} ${ampm}: ${critical.length} critical, ${warning.length} warning, ${onTrack.length} on track`;

return [{ json: { text: fallback, blocks } }];

return [{ json: {
  text: ':x: *Unified Hourly Alert failed*\n' + ($input.first().json.error || $input.first().json.message || 'Unknown error — check n8n execution log.')
} }];
